          sideState.lastReason = `\u5355\u817F\u4FDD\u62A4\u51B7\u5374\u4E2D\uFF0C\u5269\u4F59 ${getSingleLegCooldownRemainingSeconds(singleLegRuntime)} \u79D2`;
