      sideState.lastError = null;
      sideState.lastReason = `\u81EA\u52A8\u5F00\u4ED3\u5DF2\u6267\u884C\uFF0C\u51B7\u5374 ${row.auto_open_cooldown_seconds} \u79D2\u540E\u53EF\u7EE7\u7EED\u8865\u4ED3`;
